/**
 * Eval gate configuration that must pass with a fresh verdict before runs proceed.
 *
 * `block_on_failure` controls what happens at update or rollback apply time:
 * when `Some(true)`, the control plane rejects the apply if the latest eval
 * verdict has failed or has expired beyond `max_age_seconds`. The default
 * (`None`/`false`) preserves the original freshness-only behavior for
 * back-compat.
 *
 * `schedule` is an operator-supplied cron expression that asks the control
 * plane to run the gated eval set on a fixed cadence so freshness stays
 * current without manual triggering. The actual scheduling-loop dispatch is
 * owned by the eval-set scheduler today (see `CloudEvalSetSchedule`); this
 * field records the operator intent on the deployment side.
 *
 * `drift_baseline` is captured by the apply path when an update or rollback
 * commits with a passing gate. Subsequent eval runs compare against the
 * baseline so operators see regressions explicitly.
 */
export type EvalGate = {
    block_on_failure?: boolean | null;
    drift_baseline?: null | EvalGateDriftBaseline;
    max_age_seconds: number;
    schedule?: null | EvalGateSchedule;
    set_id: string;
};

/**
 * Snapshot of an eval-set verdict captured at the last successful apply.
 * Subsequent eval runs (manual or scheduled) compare against this snapshot
 * to surface drift; the apply path overwrites this value on every commit.
 */
export type EvalGateDriftBaseline = {
    baseline_captured_at: string;
    baseline_failed: number;
    baseline_passed: number;
    baseline_run_id: string;
    baseline_set_id: string;
};

/**
 * Cron-driven cadence requested by the operator for an eval gate. The
 * timezone is an IANA name (e.g. `UTC`, `America/New_York`); when omitted the
 * control plane defaults to UTC.
 */
export type EvalGateSchedule = {
    /**
     * Standard 5-field cron expression. Validated against the same parser
     * that backs deployment cron schedules.
     */
    cron: string;
    /**
     * Optional IANA timezone. Defaults to `UTC` when absent.
     */
    timezone?: string | null;
};

export type ManagedAgentApprovalPolicy = 'read_only' | 'allow_mutations';

export type ManagedAgentLlmConnection = {
    provider: 'seren_private_models';
};

export type ManagedAgentModelPolicy = 'fast' | 'balanced' | 'deep';

export type ManagedAgentRuntimeAdapter = 'seren_agent';

export type ManagedAgentSummary = {
    allowed_publisher_operations: Array<string>;
    allowed_remote_agent_origins?: Array<string>;
    approval_policy: ManagedAgentApprovalPolicy;
    build_target: string;
    model_policy: ManagedAgentModelPolicy;
    publisher: string;
    resolved_tools: Array<string>;
    routing_reason: string;
    runtime_adapter: string;
    target_framework: string;
    template: ManagedAgentTemplate;
    tool_presets: Array<ManagedAgentToolPreset>;
};

export type ManagedAgentTemplate = 'research_monitor' | 'workflow_agent';

export type ManagedAgentToolPreset = 'live_data' | 'publisher_actions' | 'database';

/**
 * Cloud deployment orchestration mode.
 *
 * `Script` (default): container runs user code directly (existing behavior).
 * `Llm`: container runs the seren-orchestrator LLM tool-calling loop.
 */
export type OrchestrationMode = 'script' | 'llm';

/**
 * Pagination metadata included in responses.
 */
export type PaginationMeta = {
    /**
     * Number of items in this response
     */
    count: number;
    /**
     * Whether there are more items after this page
     */
    has_more: boolean;
    /**
     * Maximum items per page
     */
    limit: number;
    /**
     * Offset from start
     */
    offset: number;
    /**
     * Total number of items across all pages
     */
    total: number;
};

/**
 * Request body for promoting a run into a reusable eval case.
 */
export type PromoteRunToCloudEvalCaseRequest = {
    metadata?: unknown;
    name?: string | null;
};

/**
 * Where a deployment requirement should be satisfied from.
 */
export type RequirementSource = 'env' | 'secret' | 'config';

/**
 * A declared requirement for a cloud deployment (validated at deploy time).
 */
export type RequirementSpec = {
    description?: string | null;
    key: string;
    source: RequirementSource;
};

/**
 * Deployment-level safety controls for mutating built-in publisher calls.
 */
export type SideEffectPolicy = {
    max_mutating_calls_per_run?: number | null;
    min_seconds_between_mutating_calls?: number | null;
    require_idempotency_key?: boolean;
};

/**
 * Condition for a conditional approval rule.
 */
export type ToolApprovalCondition = {
    gte?: number | null;
    lte?: number | null;
    path: string;
    type: 'numeric_threshold';
} | {
    path: string;
    type: 'string_equals';
    value: string;
} | {
    path: string;
    type: 'string_in';
    values: Array<string>;
} | {
    path: string;
    type: 'string_not_in';
    values: Array<string>;
} | {
    path: string;
    type: 'boolean_equals';
    value: boolean;
} | {
    end_hour: number;
    start_hour: number;
    type: 'outside_hours_utc';
};

/**
 * Conditional approval rule for an orchestration tool.
 */
export type ToolApprovalRule = {
    approval_reason?: string | null;
    approval_type?: ToolApprovalType;
    conditions?: Array<ToolApprovalCondition>;
};

/**
 * Approval policy for an LLM orchestration tool.
 */
export type ToolApprovalType = 'none' | 'required' | 'audit';

/**
 * A single tool definition for LLM orchestration.
 */
export type ToolDefinition = {
    approval_reason?: string | null;
    approval_rules?: Array<ToolApprovalRule>;
    approval_type?: ToolApprovalType;
    description: string;
    input_schema?: unknown;
    /**
     * Maximum output size in bytes for this tool. Output exceeding this limit is truncated.
     */
    max_output_bytes?: number | null;
    name: string;
    /**
     * Whether this tool can perform non-read work. Side-effecting tools are
     * protected so an interrupted run never silently re-runs them; set `false`
     * only for deterministic, side-effect-free reads.
     */
    side_effecting?: boolean | null;
    /**
     * Per-tool timeout override in seconds. Overrides the deployment-level tool timeout.
     */
    timeout_override_seconds?: number | null;
};

